using System.Data;
using Dapper;
using Microsoft.Extensions.Logging;
using Valora.Application.Contracts;
using Valora.Application.Security;
namespace Valora.Infrastructure.Repositories;
public sealed class CommunicationRepository(IDbConnectionFactory f, ILogger<CommunicationRepository> logger):ICommunicationRepository{ public async Task AddEmailJobAsync(Guid responseId,string toEmail,string status){try{using var c=f.Create(); await c.ExecuteAsync("INSERT INTO valorapesquisa.email_jobs(response_id,recipient_email,subject,template_key,status) VALUES (@responseId,@toEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready',@status)",new{responseId,toEmail,status});}catch(Exception ex){logger.LogError(ex,"Erro ao criar job de e-mail. ResponseId={ResponseId} Recipient={Recipient} Status={Status}",responseId,LogSanitizer.MaskEmail(toEmail),status);throw;}} public async Task<IReadOnlyList<dynamic>> ListAsync(Guid? organizationId=null){try{using var c=f.Create(); return (await c.QueryAsync("SELECT * FROM valorapesquisa.communications WHERE (@organizationId IS NULL OR organization_id=@organizationId) ORDER BY created_at DESC LIMIT 100",new{organizationId})).ToList();}catch(Exception ex){logger.LogError(ex,"Erro ao listar comunicações. OrganizationId={OrganizationId}",organizationId);throw;}} public async Task CreateEmailJobAsync(Guid organizationId,Guid responseId,string recipientEmail,string status,IDbTransaction tx){try{await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.email_jobs(organization_id,response_id,recipient_email,subject,template_key,status,payload_json) VALUES (@organizationId,@responseId,@recipientEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready',@status,jsonb_build_object('responseId',@responseId))",new{organizationId,responseId,recipientEmail,status},tx);}catch(Exception ex){logger.LogError(ex,"Erro ao criar job transacional de e-mail. OrganizationId={OrganizationId} ResponseId={ResponseId} Recipient={Recipient} Status={Status}",organizationId,responseId,LogSanitizer.MaskEmail(recipientEmail),status);throw;}} public async Task CreateCommunicationAsync(Guid organizationId,Guid surveyId,Guid responseId,string channel,string eventType,string status,string? recipientMasked,IDbTransaction tx){try{await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.communications(organization_id,survey_id,response_id,channel,event_type,status,recipient_masked) VALUES (@organizationId,@surveyId,@responseId,@channel,@eventType,@status,@recipientMasked)",new{organizationId,surveyId,responseId,channel,eventType,status,recipientMasked},tx);}catch(Exception ex){logger.LogError(ex,"Erro ao criar comunicação. OrganizationId={OrganizationId} SurveyId={SurveyId} ResponseId={ResponseId} Channel={Channel} EventType={EventType}",organizationId,surveyId,responseId,channel,eventType);throw;}}}
